  .ot-list .table-container { margin: 6px 0; font-family: "Times New Roman", serif; }
  .ot-list .data-table { width: 100%; border-collapse: collapse; border: 1px solid #000; font-size: 11px; }
  .ot-list .data-table th { background-color: #f5f5f5; border: 1px solid #000; padding: 2px; text-align: center; font-weight: bold; vertical-align: middle; font-size: 10px; }
  .ot-list .data-table th .vietnamese { font-style: italic; font-weight: normal; }
  .ot-list .data-table td { border: 1px solid #000; padding: 2px; text-align: center; vertical-align: middle; }
