<div class="ot-list">
<div class="table-container">
    <table class="data-table">
      <thead>
        <tr>
          <th style="width: 4%;">No<br><span class="vietnamese">STT</span></th>
          <th style="width: 26%;">Employee<br><span class="vietnamese">Nhân viên</span></th>
          <th style="width: 8%;">Group<br><span class="vietnamese">Nhóm</span></th>
          <th style="width: 26%;">Date<br><span class="vietnamese">Ngày</span></th>
          <th style="width: 26%;">Reason<br><span class="vietnamese">Lý do</span></th>
          <th style="width: 10%;">Signature<br><span class="vietnamese">Chữ ký</span></th>
        </tr>
      </thead>
      <tbody>
        {% set employee_data = {} %}
        <!-- Group rows by employee; keep each day's times paired with its date -->
        {% for row in doc.ot_employees %}
        {% if row.employee not in employee_data %}
        {% set _ = employee_data.update({
        row.employee: {
        'employee_name': row.employee_name,
        'groups': [],
        'entries': [],
        'reasons': []
        }
        }) %}
        {% endif %}
        {% set data = employee_data[row.employee] %}
        {% if row.group and row.group not in data['groups'] %}
        {% set _ = data['groups'].append(row.group) %}
        {% endif %}
        {% if row.date %}
        {% set begin_str = (row.begin_time|string)[:5] if row.begin_time else "" %}
        {% set end_str = (row.end_time|string)[:5] if row.end_time else "" %}
        {% set _ = data['entries'].append({'date': row.date, 'begin': begin_str, 'end': end_str}) %}
        {% endif %}
        {% if row.reason and row.reason not in data['reasons'] %}
        {% set _ = data['reasons'].append(row.reason) %}
        {% endif %}
        {% endfor %}
        {% for employee_id, data in employee_data.items() %}
        <tr>
          <td>{{ loop.index }}</td>
          <td class="text-left"><b>{{ employee_id }}</b> - {{ data.employee_name or "" }}</td>
          <td>{{ data['groups'] | join(", ") }}</td>
          <td class="date-cell">
            {% for e in data['entries'] | sort(attribute='date') %}
            {{ frappe.utils.formatdate(e.date, "dd/MM/yy") }}{% if e.begin and e.end %}: {{ e.begin }} - {{ e.end }}{% endif %}{% if not loop.last %}<br>{% endif %}
            {% endfor %}
          </td>
          <td class="text-left">
            {% for reason in data['reasons'] %}
            {{ reason }}{% if not loop.last %}<br>{% endif %}
            {% endfor %}
          </td>
          <td style="height: 20px;"></td>
        </tr>
        {% endfor %}
      </tbody>
    </table>
  </div>
</div>
